#include <iostream>

class Coordinate {
private:
    int x_val;
    int y_val;

public:
    Coordinate(int x, int y) : x_val(x), y_val(y) {}

    int getX() const {
        return x_val;
    }

    int getY() const {
        return y_val;
    }

    void setX(int newX) {
        x_val = newX;
    }
};

int main() {
    const Coordinate c(10, 20);
    std::cout << "Const object c.getX(): " << c.getX() << std::endl;
    std::cout << "Const object c.getY(): " << c.getY() << std::endl;
    // c.setX(30); // This line would cause a semantic error.
    return 0;
}
